import React, {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState
} from 'react';
import './App.css';

type Candidate = {
  id: string;
  name: string;
  email: string;
};

type Chip = {
  id: string;
  label: string;
  value: string;
};

const MAX_INVITES = 5;
const MAX_SUGGESTIONS = 6;
const LISTBOX_ID = 'invite-suggestions';

const USERS: Candidate[] = [
  { id: 'ada', name: 'Ada Lovelace', email: 'ada@frontendatlas.dev' },
  { id: 'alice', name: 'Alice Johnson', email: 'alice@frontendatlas.dev' },
  { id: 'bob', name: 'Bob Smith', email: 'bob@frontendatlas.dev' },
  { id: 'charlie', name: 'Charlie Kim', email: 'charlie@frontendatlas.dev' },
  { id: 'diana', name: 'Diana Lopez', email: 'diana@frontendatlas.dev' },
  { id: 'ethan', name: 'Ethan Brown', email: 'ethan@frontendatlas.dev' },
  { id: 'fiona', name: 'Fiona Patel', email: 'fiona@frontendatlas.dev' },
  { id: 'george', name: 'George Miller', email: 'george@frontendatlas.dev' }
];

function normalize(value: string): string {
  return value.trim().toLowerCase();
}

function toChip(candidate: Candidate): Chip {
  return {
    id: candidate.id,
    label: candidate.name,
    value: candidate.email
  };
}

function optionId(item: Chip): string {
  return 'invite-option-' + item.id;
}

export default function App() {
  const comboboxRef = useRef<HTMLDivElement | null>(null);
  const [chips, setChips] = useState<Chip[]>([]);
  const [query, setQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [status, setStatus] = useState('');

  const atLimit = chips.length >= MAX_INVITES;

  const suggestions = useMemo<Chip[]>(() => {
    const needle = normalize(query);
    if (!needle || atLimit) return [];

    const selectedIds = new Set(chips.map((chip) => chip.id));
    const selectedLabels = new Set(chips.map((chip) => normalize(chip.label)));
    const selectedValues = new Set(chips.map((chip) => normalize(chip.value)));

    return USERS
      .filter((candidate) => {
        if (
          selectedIds.has(candidate.id) ||
          selectedLabels.has(normalize(candidate.name)) ||
          selectedValues.has(normalize(candidate.email))
        ) {
          return false;
        }

        return (
          normalize(candidate.name).includes(needle) ||
          normalize(candidate.email).includes(needle)
        );
      })
      .slice(0, MAX_SUGGESTIONS)
      .map(toChip);
  }, [atLimit, chips, query]);

  const closeSuggestions = useCallback(() => {
    setIsOpen(false);
    setActiveIndex(-1);
  }, []);

  const addChip = useCallback((chip: Chip) => {
    setChips((current) => {
      const existing = current.find(
        (item) =>
          item.id === chip.id ||
          normalize(item.label) === normalize(chip.label) ||
          normalize(item.value) === normalize(chip.value)
      );

      if (existing) {
        setStatus(existing.label + ' is already invited.');
        return current;
      }

      if (current.length >= MAX_INVITES) {
        setStatus('Invite limit reached. Remove a person to add another.');
        return current;
      }

      const next = [...current, chip];
      setStatus(
        next.length === MAX_INVITES
          ? 'Invite limit reached. Remove a person to add another.'
          : chip.label + ' added. ' + next.length + ' of 5 invites used.'
      );
      return next;
    });

    setQuery('');
    closeSuggestions();
  }, [closeSuggestions]);

  const addCustomFromQuery = useCallback(() => {
    const label = query.trim();

    if (!label) {
      setQuery('');
      closeSuggestions();
      return;
    }

    addChip({
      id: 'custom-' + encodeURIComponent(normalize(label)),
      label,
      value: label
    });
  }, [addChip, closeSuggestions, query]);

  const removeChip = useCallback((chipId: string) => {
    setChips((current) => {
      const removed = current.find((chip) => chip.id === chipId);
      if (!removed) return current;

      const next = current.filter((chip) => chip.id !== chipId);
      setStatus(
        removed.label + ' removed. ' + next.length + ' of 5 invites used.'
      );
      return next;
    });
  }, []);

  const selectSuggestion = useCallback((chip: Chip) => {
    addChip(chip);
  }, [addChip]);

  function handleKeyDown(event: React.KeyboardEvent<HTMLInputElement>) {
    const suggestionCount = suggestions.length;

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      if (!suggestionCount) return;
      setIsOpen(true);
      setActiveIndex((current) =>
        current < 0 ? 0 : (current + 1) % suggestionCount
      );
      return;
    }

    if (event.key === 'ArrowUp') {
      event.preventDefault();
      if (!suggestionCount) return;
      setIsOpen(true);
      setActiveIndex((current) =>
        current < 0
          ? suggestionCount - 1
          : (current - 1 + suggestionCount) % suggestionCount
      );
      return;
    }

    if (event.key === 'Enter') {
      event.preventDefault();
      const activeSuggestion = suggestions[activeIndex];
      if (isOpen && activeSuggestion) {
        selectSuggestion(activeSuggestion);
      } else {
        addCustomFromQuery();
      }
      return;
    }

    if (event.key === ',') {
      event.preventDefault();
      addCustomFromQuery();
      return;
    }

    if (event.key === 'Backspace' && query.length === 0 && chips.length > 0) {
      event.preventDefault();
      removeChip(chips[chips.length - 1].id);
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      closeSuggestions();
    }
  }

  function handleInputChange(event: React.ChangeEvent<HTMLInputElement>) {
    setQuery(event.target.value);
    setActiveIndex(-1);
  }

  useEffect(() => {
    const shouldOpen =
      !atLimit && normalize(query).length > 0 && suggestions.length > 0;

    setIsOpen(shouldOpen);
    setActiveIndex((current) =>
      shouldOpen && current < suggestions.length ? current : -1
    );
  }, [atLimit, query, suggestions.length]);

  useEffect(() => {
    function handleDocumentMouseDown(event: MouseEvent) {
      const target = event.target as Node | null;
      if (!target || !comboboxRef.current) return;

      if (!comboboxRef.current.contains(target)) {
        closeSuggestions();
      }
    }

    document.addEventListener('mousedown', handleDocumentMouseDown);
    return () => {
      document.removeEventListener('mousedown', handleDocumentMouseDown);
    };
  }, [closeSuggestions]);

  const activeSuggestion = suggestions[activeIndex];
  const activeDescendant =
    isOpen && activeSuggestion ? optionId(activeSuggestion) : undefined;
  const limitText = atLimit
    ? 'Invite limit reached (5 of 5).'
    : chips.length + ' of 5 invites used.';

  return (
    <main className="page">
      <section className="card" aria-labelledby="invite-title">
        <header className="header">
          <h1 id="invite-title">Invite people</h1>
          <p className="subtitle">
            Add teammates by name or email, or create a custom invite.
          </p>
        </header>

        <div ref={comboboxRef} className="combobox">
          <label className="field-label" htmlFor="invite-input">
            People
          </label>

          <div className="chip-field">
            {chips.map((chip) => (
              <span className="chip" key={chip.id}>
                <span className="chip-label">{chip.label}</span>
                <button
                  type="button"
                  className="chip-remove"
                  onClick={() => removeChip(chip.id)}
                  aria-label={'Remove ' + chip.label}
                >
                  ×
                </button>
              </span>
            ))}

            <input
              id="invite-input"
              className="chip-input"
              type="text"
              role="combobox"
              value={query}
              onChange={handleInputChange}
              onFocus={() => {
                if (!atLimit && normalize(query) && suggestions.length) {
                  setIsOpen(true);
                }
              }}
              onKeyDown={handleKeyDown}
              disabled={atLimit}
              placeholder={
                atLimit ? 'Remove an invite to add another' : 'Type a name or email...'
              }
              autoComplete="off"
              aria-autocomplete="list"
              aria-haspopup="listbox"
              aria-controls={LISTBOX_ID}
              aria-describedby="invite-hint invite-limit"
              aria-expanded={isOpen}
              aria-activedescendant={activeDescendant}
            />
          </div>

          {isOpen && (
            <ul
              id={LISTBOX_ID}
              className="suggestions"
              role="listbox"
              aria-label="Invite suggestions"
            >
              {suggestions.map((item, index) => (
                <li
                  key={item.id}
                  id={optionId(item)}
                  role="option"
                  aria-selected={index === activeIndex}
                  className={
                    index === activeIndex ? 'suggestion active' : 'suggestion'
                  }
                  onMouseDown={(event) => {
                    event.preventDefault();
                    selectSuggestion(item);
                  }}
                  onClick={() => selectSuggestion(item)}
                >
                  <strong>{item.label}</strong>
                  <span>{item.value}</span>
                </li>
              ))}
            </ul>
          )}
        </div>

        <p id="invite-hint" className="hint">
          Arrow keys navigate. Enter or comma adds. Empty Backspace removes the last invite.
        </p>
        <p id="invite-limit" className="invite-limit">
          {limitText}
        </p>
        <p
          className="invite-status"
          role="status"
          aria-live="polite"
          aria-atomic="true"
        >
          {status}
        </p>
      </section>
    </main>
  );
}
